# S46-T1-A-E2 explorer: three routes for domain contract
record = {"case_id": "CASO-HYO-046-1A", **{"event_time":110,"window_end":120,"watermark":115,"allowed_lateness":10}}
valid = record
# adverse flips domain-critical signal
invalid = {**valid, **{k: (not v if isinstance(v, bool) else v) for k, v in list(valid.items()) if k != "case_id"}}
# stronger adverse: ensure fixed_pred is False
def _force_fail(rec):
    bad = dict(rec)
    # try common fail knobs
    for k, v in list(bad.items()):
        if k == "case_id":
            continue
        if isinstance(v, bool) and v is True:
            bad[k] = False
            return bad
        if isinstance(v, bool) and v is False and k in ("secret_baked", "debug_shell", "shared_database", "infers_fraud", "cache_authoritative", "leakage", "overlap", "side_effect", "forbidden_tool_used", "pii_in_trace", "holdout_touched"):
            bad[k] = True
            return bad
        if isinstance(v, (int, float)) and k.endswith(("_cves", "error_rate", "open_p0", "open_p1")):
            bad[k] = 1
            return bad
    bad["_broken"] = True
    return bad
invalid = _force_fail(valid)
incomplete = {k: v for k, v in valid.items() if k != "allowed_lateness"}

def assess(record: dict) -> str:
    required = {"case_id", "event_time", "window_end", "watermark", "allowed_lateness"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    record_local = record  # alias for predicate using name record
    record = record_local
    ok = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    return "PASS" if ok else "SIDE_OUTPUT_LATE_EVENT"

results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

